async (page) => {
  // Move to and click oak at (206, 118)
  const move = await page.evaluate(({x, y}) => JSON.stringify(window.__moveTo(x, y)), {x: 207, y: 118});
  await page.waitForTimeout(2000);
  // Now click the tree tile
  const click = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 206, y: 118});
  await page.waitForTimeout(5000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const logCount = parsed.inventory.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0);
  return JSON.stringify({ logs: logCount, pos: parsed.player_position, target: parsed.current_target ? parsed.current_target.name : null, lumberjacking: parsed.skills.Lumberjacking, last_xp: parsed.last_xp_event });
}

async (page) => {
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__navigateTo(x, y)), {x: 216, y: 115});
