  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ pos: parsed.player_position, nav: parsed.navigation });
}

async (page) => {
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__moveTo(x, y)), {x: 216, y: 115});
  await page.waitForTimeout(3000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
